3147 /// Given a call CB which uses an address UsedV, return true if we can prove the
3148 /// call's only possible effect is storing to V.
3149 static bool isRemovableWrite(CallBase &CB, Value *UsedV,
3150                              const TargetLibraryInfo &TLI) {
3151   if (!CB.use_empty())
3152     // TODO: add recursion if returned attribute is present
3153     return false;
3154 
3155   if (CB.isTerminator())
3156     // TODO: remove implementation restriction
3157     return false;
3158 
3159   if (!CB.willReturn() || !CB.doesNotThrow())
3160     return false;
3161 
3162   // If the only possible side effect of the call is writing to the alloca,
3163   // and the result isn't used, we can safely remove any reads implied by the
3164   // call including those which might read the alloca itself.
3165   std::optional<MemoryLocation> Dest = MemoryLocation::getForDest(&CB, TLI);
3166   return Dest && Dest->Ptr == UsedV;
